-- Create a secure view that filters rows based on current user
CREATE VIEW my_documents AS
SELECT d.id, d.title, d.content, d.created_at
FROM documents d
WHERE d.owner_id = (
    SELECT id FROM users WHERE username = SUBSTRING_INDEX(USER(), '@', 1)
)
OR d.id IN (
    SELECT document_id FROM document_shares 
    WHERE shared_with_user = SUBSTRING_INDEX(USER(), '@', 1)
    AND expires_at > NOW()
);

-- Grant access only through the view
GRANT SELECT ON my_documents TO 'app_user'@'%';
REVOKE SELECT ON documents FROM 'app_user'@'%';
